def transform(input_data):
    rows = input_data if isinstance(input_data, list) else []
    by_origin = {}
    for row in rows:
        origin = row.get('origin', 'unknown')
        agg = by_origin.setdefault(origin, {'count': 0, 'mpg_total': 0.0, 'hp_total': 0.0})
        agg['count'] += 1
        agg['mpg_total'] += row.get('mpg', 0.0)
        agg['hp_total'] += row.get('hp', 0.0)

    summary = []
    for origin, agg in sorted(by_origin.items()):
        count = agg['count']
        summary.append({
            'origin': origin,
            'count': count,
            'avg_mpg': round(agg['mpg_total'] / count, 2),
            'avg_hp': round(agg['hp_total'] / count, 2),
        })

    return {'dataset': 'vega-cars', 'rows_processed': len(rows), 'summary_by_origin': summary}
